#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=500005;
ll n,s[N],a[N],sum,dp[N];
stack<int> st;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=n;i++)
	{
		while(!st.empty()&&a[i]>=a[st.top()])
		{
			if(a[i]==a[st.top()]) dp[i]=dp[st.top()]+1;
			sum+=(dp[st.top()]+1);
			st.pop();
		}
		if(!st.empty()) sum++;
		st.push(i);
	}
	cout<<sum;
	return 0;
}
